(function() {
    console.log("Axiom Bot Validator active! টাইপিং শুরু হচ্ছে...");

    // delay helper
    function delay(ms) {
        return new Promise(resolve => setTimeout(resolve, ms));
    }

    // টাইপিং ইফেক্ট
    async function typeEffect(element, text) {
        if (!element) return;
        element.focus();
        element.value = "";

        for (let char of text) {
            element.value += char;
            element.dispatchEvent(new Event('input', { bubbles: true }));
            element.dispatchEvent(new Event('change', { bubbles: true }));
            await delay(50);
        }
    }

    // 🔁 MAIN LOOP FUNCTION
    async function startAutomationLoop() {

        while (true) { // 🔥 infinite loop শুরু

            console.log("🚀 নতুন রান শুরু হচ্ছে...");

            // --- স্ক্রিন ১ ---
            let fname = document.getElementById('fname');
            let lname = document.getElementById('lname');

            if (fname && lname) {
                await typeEffect(fname, "Axiom");
                await typeEffect(lname, "Browser");
                await delay(500);
                document.querySelector('#screen1 .btn-next').click();
            }

            // --- স্ক্রিন ২ ---
            await delay(1000);
            let day = document.getElementById('day');
            let month = document.getElementById('month');
            let year = document.getElementById('year');

            if (day && month && year) {
                await typeEffect(day, "16");
                await typeEffect(month, "02");
                await typeEffect(year, "2026");
                await delay(500);
                document.querySelector('#screen2 .btn-next').click();
            }

            // --- স্ক্রিন ৩ ---
            await delay(1000);
            let email = document.getElementById('email');

            if (email) {
                await typeEffect(email, "axiom" +  "@bot.com");
                await delay(500);
                document.querySelector('#screen3 .btn-next').click();
            }

            // --- স্ক্রিন ৪ ---
            await delay(1000);
            let pass = document.getElementById('pass');

            if (pass) {
                await typeEffect(pass, "SecurePass123");
                await delay(500);
                document.querySelector('#screen4 .btn-next').click();
            }

            console.log("✅ একবার কাজ শেষ!");

            // 🔁 আবার শুরু করার আগে একটু অপেক্ষা
            await delay(1500);
        }
    }

    // চালু করো
    startAutomationLoop();

})();
